import{_ as e,c as a,o as i,b as c}from"./app.8154329a.js";const b=JSON.parse('{"title":"React","description":"","frontmatter":{"layout":"doc","title":"React"},"headers":[{"level":2,"title":"webpack 的构建流程","slug":"webpack-的构建流程","link":"#webpack-的构建流程","children":[]},{"level":2,"title":"Webpack 的热更新原理","slug":"webpack-的热更新原理","link":"#webpack-的热更新原理","children":[]}],"relativePath":"interview/webpack.md"}'),t={name:"interview/webpack.md"},l=c('<h1 id="webpack-相关基础" tabindex="-1">Webpack 相关基础 <a class="header-anchor" href="#webpack-相关基础" aria-hidden="true">#</a></h1><h2 id="webpack-的构建流程" tabindex="-1">webpack 的构建流程 <a class="header-anchor" href="#webpack-的构建流程" aria-hidden="true">#</a></h2><ul><li>初始化参数：从配置文件读取与合并参数，得出最终的参数</li><li>开始编译：用上一步得到的参数初始化 Compiler 对象，加载所有配置的插件，开始执行编译</li><li>确定入口：根据配置中的 entry 找出所有的入口文件</li><li>编译模块：从入口文件出发，调用所有配置的 Loader 对模块进行翻译，再找出该模块依赖的模块，再递归本步骤直到所有入口依赖的文件都经过了本步骤的处理</li><li>完成模块编译：在经过第 4 步使用 Loader 翻译完所有模块后，得到了每个模块被翻译后的最终内容以及它们之间的依赖关系</li><li>输出资源：根据入口和模块之间的依赖关系，组装成一个个包含多个模块的 Chunk，再把每个 Chunk 转换成一个单独的文件加入到输出列表，这步是可以修改输出内容的最后机会</li><li>输出完成：在确定好输出内容后，根据配置确定输出的路径和文件名，把文件内容写入到文件系统。</li></ul><p>在以上过程中，webpack 会在特定的时间点广播出特定的事件，plugin 监听相关事件后会执行特定的逻辑</p><h2 id="webpack-的热更新原理" tabindex="-1">Webpack 的热更新原理 <a class="header-anchor" href="#webpack-的热更新原理" aria-hidden="true">#</a></h2>',5),r=[l];function n(p,d,o,s,h,_){return i(),a("div",null,r)}const w=e(t,[["render",n]]);export{b as __pageData,w as default};
